    \draw[gray!20, step=1] (0,0) grid (6,5);

    \draw[fill=green!10, thick] (0,0) -- (5,1) -- (4,4) -- (1,3) -- cycle;

    \draw[->, very thick, red!65!black] (0,0) -- (2.3,0.46);
    \draw[->, very thick, red!65!black] (5,1) -- (4.55,2.35);
    \draw[->, very thick, red!65!black] (4,4) -- (2.55,3.55);
    \draw[->, very thick, red!65!black] (1,3) -- (0.45,1.35);

    \foreach \p/\name in {(0,0)/P_0,(5,1)/P_1,(4,4)/P_2,(1,3)/P_3} {
        \fill \p circle (2.5pt);
        \node[above right] at \p {\(\name\)};
    }

    \node at (3,-0.9) {area from boundary data};
\end{tikzpicture}

subsection.p:
Now compute the outward flux through the six faces.
\begin{array}{c|c|c|c} \text{Face} \amp \widehat{\mathbf n} \amp \mathbf J\cdot\widehat{\mathbf n} \amp \text{Flux} \\ \hline x=1 \amp (1,0,0) \amp 1 \amp 1\\ x=0 \amp (-1,0,0) \amp 0 \amp 0\\ y=1 \amp (0,1,0) \amp 1 \amp 1\\ y=0 \amp (0,-1,0) \amp 0 \amp 0\\ z=1 \amp (0,0,1) \amp 1 \amp 1\\ z=0 \amp (0,0,-1) \amp 0 \amp 0 \end{array}
So the total outward flux is
1+0+1+0+1+0=3.
The two sides match:
\boxed{ \iint_{\partial E}\mathbf J\cdot\widehat{\mathbf n}\,dS = \iiint_E\nabla\cdot\mathbf J\,dV = 3. }
